+    p_collection_name TEXT,
+    p_query vector,
+    p_k INTEGER,
+    p_exactness ruvector.exactness_mode DEFAULT NULL,  -- NULL = use collection default
+    p_ef_search INTEGER DEFAULT NULL
+) RETURNS TABLE (
