+             FROM ruvector.collections c
+             JOIN ruvector.tier_policies tp ON c.id = tp.collection_id
+             WHERE tp.enabled = true
+             GROUP BY c.id",
+            None,
+            &[],
+        )?.map(|row| {
+            Ok(CollectionInfo {
+                id: row.get::<i32>(1)?,
+                name: row.get::<String>(2)?,
+            })
+        }).collect()
+    })
