+CREATE FUNCTION ruvector_retrain_compression(
+    p_collection_name TEXT,
+    p_sample_size INTEGER DEFAULT 10000
+) RETURNS JSONB AS 'MODULE_PATHNAME', 'ruvector_retrain_compression' LANGUAGE C;
